protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF 9 renamed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference it.
        entity.HasDiscriminator<string>("Discriminator");

        // EF 9 no longer prepends the discriminator to the JSON id.
        // Existing documents store id as "Product|123"; preserve that format.
        entity.HasDiscriminatorInJsonId();

        // EF 9 maps the key property directly to the JSON "id" field, dropping
        // the former shadow __id property. Existing documents still carry a
        // separate "Id" property in the body; keep the shadow id to stay compatible.
        entity.HasShadowId();
    });
}

